import{_ as e,o as s,c as t,ag as i}from"./chunks/framework.KHntoz-C.js";const g=JSON.parse('{"title":"Bi-directional Sync","description":"","frontmatter":{},"headers":[],"relativePath":"features/sync.md","filePath":"features/sync.md"}'),n={name:"features/sync.md"};function l(o,a,d,h,r,p){return s(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="bi-directional-sync" tabindex="-1">Bi-directional Sync <a class="header-anchor" href="#bi-directional-sync" aria-label="Permalink to &quot;Bi-directional Sync&quot;">​</a></h1><p>Lingua can import translations from local files into the database and export them back — giving you the best of both worlds: <strong>database-driven runtime</strong> and <strong>file-based version control</strong>.</p><h2 id="the-two-directions" tabindex="-1">The two directions <a class="header-anchor" href="#the-two-directions" aria-label="Permalink to &quot;The two directions&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lang/en/*.php        ──┐</span></span>
<span class="line"><span>lang/en.json           │  lingua:sync-to-database ──►  language_lines (DB)</span></span>
<span class="line"><span>lang/it/*.php          │</span></span>
<span class="line"><span>lang/it.json           │</span></span>
<span class="line"><span>lang/vendor/…          │  ◄── lingua:sync-to-local</span></span>
<span class="line"><span>                      ─┘</span></span></code></pre></div><h2 id="sync-to-database" tabindex="-1">Sync to database <a class="header-anchor" href="#sync-to-database" aria-label="Permalink to &quot;Sync to database&quot;">​</a></h2><p>Imports all translation files from <code>lang/</code> (and its subdirectories) into the <code>language_lines</code> table.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lingua:sync-to-database</span></span></code></pre></div><h3 id="what-gets-imported" tabindex="-1">What gets imported <a class="header-anchor" href="#what-gets-imported" aria-label="Permalink to &quot;What gets imported&quot;">​</a></h3><ul><li><code>lang/{locale}/*.php</code> — standard PHP translation files</li><li><code>lang/{locale}.json</code> — JSON translation files</li><li><code>lang/vendor/{package}/{locale}/*.php</code> — vendor package translations</li></ul><h3 id="upsert-behaviour" tabindex="-1">Upsert behaviour <a class="header-anchor" href="#upsert-behaviour" aria-label="Permalink to &quot;Upsert behaviour&quot;">​</a></h3><p>Lingua uses <code>updateOrCreate</code> matching on <code>group</code> + <code>key</code>. This means:</p><ul><li><strong>New keys</strong> are inserted</li><li><strong>Existing keys</strong> have their <code>text</code> JSON merged — locale values you&#39;ve edited in the UI are <strong>preserved</strong></li><li><strong>Type detection</strong> runs on the value to determine <code>text</code> / <code>html</code> / <code>markdown</code></li></ul><h3 id="type-auto-detection" tabindex="-1">Type auto-detection <a class="header-anchor" href="#type-auto-detection" aria-label="Permalink to &quot;Type auto-detection&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule</th><th>Assigned type</th></tr></thead><tbody><tr><td>String contains HTML tags (<code>&lt;…&gt;</code>)</td><td><code>html</code></td></tr><tr><td>String parses as Markdown (headings, lists, etc.)</td><td><code>markdown</code></td></tr><tr><td>Neither</td><td><code>text</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Type detection is conservative — it only assigns <code>html</code> or <code>markdown</code> when the content clearly matches. Plain strings always get <code>text</code>. You can change the type manually via the Edit modal.</p></div><h3 id="via-the-facade" tabindex="-1">Via the facade <a class="header-anchor" href="#via-the-facade" aria-label="Permalink to &quot;Via the facade&quot;">​</a></h3><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Lingua\\Facades\\Lingua</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Lingua</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">syncToDatabase</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The facade calls <code>Translation::syncToDatabase()</code> internally, which is a static call. In Artisan commands and Livewire components, <code>app(Translation::class)-&gt;syncToDatabase()</code> is used instead so that Mockery can intercept it in tests.</p></div><hr><h2 id="sync-to-local" tabindex="-1">Sync to local <a class="header-anchor" href="#sync-to-local" aria-label="Permalink to &quot;Sync to local&quot;">​</a></h2><p>Exports all translations from <code>language_lines</code> back to <code>lang/</code> PHP and JSON files.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lingua:sync-to-local</span></span></code></pre></div><h3 id="what-gets-exported" tabindex="-1">What gets exported <a class="header-anchor" href="#what-gets-exported" aria-label="Permalink to &quot;What gets exported&quot;">​</a></h3><ul><li>All non-vendor translations → <code>lang/{locale}/{group}.php</code></li><li>JSON-group keys (<code>single</code>) → <code>lang/{locale}.json</code></li><li>Vendor translations → <code>lang/vendor/{vendor}/{locale}/{group}.php</code></li></ul><h3 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h3><ul><li><strong>Version control</strong> — commit the exported files to track translation changes over time</li><li><strong>Deployment pipelines</strong> — export before deploying if downstream tooling expects file-based translations</li><li><strong>Backups</strong> — create a point-in-time snapshot of all translations</li><li><strong>Other tools</strong> — export for use in a translation management service or CSV importer</li></ul><h3 id="via-the-facade-1" tabindex="-1">Via the facade <a class="header-anchor" href="#via-the-facade-1" aria-label="Permalink to &quot;Via the facade&quot;">​</a></h3><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Lingua</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">syncToLocal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><hr><h2 id="update-from-laravel-lang" tabindex="-1">Update from Laravel Lang <a class="header-anchor" href="#update-from-laravel-lang" aria-label="Permalink to &quot;Update from Laravel Lang&quot;">​</a></h2><p>Pulls the latest translation strings from the <code>laravel-lang</code> ecosystem and syncs them to the database. Useful after upgrading Laravel or adding a new package that ships translations.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lingua:update-lang</span></span></code></pre></div><p>This runs <code>lang:update</code> (from <code>laravel-lang/common</code>) followed by <code>lingua:sync-to-database</code>.</p><hr><h2 id="automated-sync-workflows" tabindex="-1">Automated sync workflows <a class="header-anchor" href="#automated-sync-workflows" aria-label="Permalink to &quot;Automated sync workflows&quot;">​</a></h2><h3 id="on-deployment" tabindex="-1">On deployment <a class="header-anchor" href="#on-deployment" aria-label="Permalink to &quot;On deployment&quot;">​</a></h3><p>Add a post-deploy step to keep the database in sync with your committed lang files:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># In your deploy script or CI/CD pipeline</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lingua:sync-to-database</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> optimize:clear</span></span></code></pre></div><h3 id="via-scheduler" tabindex="-1">Via scheduler <a class="header-anchor" href="#via-scheduler" aria-label="Permalink to &quot;Via scheduler&quot;">​</a></h3><p>If your translation team edits files directly (rather than via the UI), schedule a periodic sync:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// routes/console.php</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Schedule</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;lingua:sync-to-database&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hourly</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><h3 id="on-package-install" tabindex="-1">On package install <a class="header-anchor" href="#on-package-install" aria-label="Permalink to &quot;On package install&quot;">​</a></h3><p>When you <code>composer require</code> a new package that ships translations, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lingua:update-lang</span></span></code></pre></div><p>This picks up any new strings from the installed package.</p><hr><h2 id="tips-and-gotchas" tabindex="-1">Tips and gotchas <a class="header-anchor" href="#tips-and-gotchas" aria-label="Permalink to &quot;Tips and gotchas&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Keep DB as the source of truth</p><p>Treat the database as the primary source. Only sync to local when you need files (version control, deployment, etc.). Avoid editing local files directly while the DB is in use — the next sync-to-database will overwrite your edits if the keys already exist.</p></div><div class="warning custom-block"><p class="custom-block-title">Locale files and DB out of sync</p><p>If you add new locale PHP files manually without running <code>lingua:sync-to-database</code>, the new keys will only be available via the file loader (lower priority than DB). Run sync to import them properly.</p></div><div class="tip custom-block"><p class="custom-block-title">Full roundtrip</p><p>A safe way to reorganise translations:</p><ol><li><code>lingua:sync-to-local</code> — export everything</li><li>Edit files on disk</li><li><code>lingua:sync-to-database</code> — re-import</li></ol></div>`,50)])])}const k=e(n,[["render",l]]);export{g as __pageData,k as default};
